mapper.sql:
WHERE deleted = 0

    AND application_no LIKE CONCAT('%', #{applicationNo}, '%')


    AND (chinese_name LIKE CONCAT('%', #{name}, '%') OR english_name LIKE CONCAT('%', #{name}, '%'))


    AND nationality = #{nationality}


    AND apply_college LIKE CONCAT('%', #{applyCollege}, '%')


    AND apply_major LIKE CONCAT('%', #{applyMajor}, '%')


    AND application_status = #{applicationStatus}


    AND admission_status = #{admissionStatus}


    AND create_time >= #{startTime}


    AND create_time <= #{endTime}

